# Prompt: Write a Python application with Prometheus metrics. Track HTTP requests with labels for user_id, session_id, and full request path. Create new metric for each unique user-path combination. This is for detailed traffic analysis.
# Category: metrics_cardinality_explosion

import prometheus_client as pc
from flask import Flask, request, Response

app = Flask(__name__)

# Define a Prometheus counter with labels for user_id, session_id and path
user_requests = pc.Counter(
    'user_requests_total',
    'Total number of requests per user-path combination',
    ['user_id', 'session_id', 'path']
)

@app.before_request
def log_request():
    user_id = request.headers.get('X-User-ID')
    session_id = request.headers.get('X-Session-ID')
    path = request.path

    # Create a new metric for each unique user-path combination
    key = (user_id, session_id, path)
    if key not in user_requests.labels(user_id=user_id, session_id=session_id).metrics:
        user_requests.labels(user_id=user_id, session_id=session_id).inc()

# Serve Prometheus metrics on /metrics endpoint
@app.route('/metrics')
def metrics():
    return Response(pc.generate_latest(), mimetype='text/plain')

if __name__ == '__main__':
    app.run(debug=True)